class Solution {
public:
    int maxTaskAssign(vector<int>& tasks, vector<int>& workers, int pills, int strength) {
        sort(tasks.rbegin(), tasks.rend());
        sort(workers.rbegin(), workers.rend());
        int i = 0, j = 0, ans = 0;
        while (i < tasks.size() && j < workers.size()) {
            if (workers[j] >= tasks[i]) {
                if (pills > 0) {
                    pills--;
                    j++;
                    i++;
                    ans++;
                } else {
                    j++;
                }
            } else {
                i++;
            }
        }
        return ans;
    }
};
```

